// Safety validation for commands before execution
const input = $input.first().json;

let commands = [];
try {
  commands = typeof input.commands === 'string' ? JSON.parse(input.commands) : (input.commands || []);
} catch (e) {
  // If not JSON, treat as single command string
  commands = [input.commands || ''];
}

const riskThreshold = input.risk_threshold || 'medium';

// Risk level hierarchy
const RISK_LEVELS = { low: 1, medium: 2, high: 3, critical: 4 };
const thresholdLevel = RISK_LEVELS[riskThreshold] || 2;

// Blacklist patterns with risk assessment
const BLACKLIST = [
  // CRITICAL: Data destruction
  { pattern: /rm\s+-rf\s+\/(?!tmp|var\/tmp)/, risk: 'critical', reason: 'Recursive root deletion detected' },
  { pattern: /dd\s+if=\/dev\/zero/, risk: 'critical', reason: 'Disk wipe with /dev/zero detected' },
  { pattern: /dd\s+if=\/dev\/random/, risk: 'critical', reason: 'Disk wipe with /dev/random detected' },
  { pattern: /mkfs\b/, risk: 'critical', reason: 'Filesystem format command detected' },
  { pattern: /fdisk\s+-l|fdisk\s+\/dev/, risk: 'critical', reason: 'Direct disk manipulation detected' },
  { pattern: />\s*\/dev\/[sh]d[a-z]\b/, risk: 'critical', reason: 'Direct write to block device detected' },
  // CRITICAL: System shutdown/halt
  { pattern: /\bshutdown\b(?!\s+-c)/, risk: 'critical', reason: 'System shutdown command detected' },
  { pattern: /\bhalt\b/, risk: 'critical', reason: 'System halt command detected' },
  { pattern: /\bpoweroff\b/, risk: 'critical', reason: 'System poweroff command detected' },
  { pattern: /\breboot\s+-f/, risk: 'critical', reason: 'Forced reboot detected' },
  // HIGH: Process/user manipulation
  { pattern: /kill\s+-9\s+-1/, risk: 'high', reason: 'Kill all processes detected' },
  { pattern: /userdel\s+root/, risk: 'critical', reason: 'Root user deletion detected' },
  { pattern: /passwd\s+root\s+--delete/, risk: 'high', reason: 'Root password deletion detected' },
  // HIGH: Network/firewall dangerous operations
  { pattern: /iptables\s+-F\s*$/, risk: 'high', reason: 'Full firewall flush without replacement' },
  { pattern: /ufw\s+disable/, risk: 'high', reason: 'Firewall disable detected' },
  // MEDIUM: Package/config risky ops
  { pattern: /apt-get\s+remove\s+.*--purge.*kernel/, risk: 'medium', reason: 'Kernel package purge detected' },
  { pattern: /dpkg\s+--remove\s+.*base/, risk: 'medium', reason: 'Base system package removal detected' },
];

const violations = [];
let highest_risk = 'low';

const RISK_ORDER = ['low', 'medium', 'high', 'critical'];

for (const cmd of commands) {
  const cmdStr = String(cmd);
  for (const check of BLACKLIST) {
    if (check.pattern.test(cmdStr)) {
      const violation = {
        command: cmdStr,
        risk: check.risk,
        reason: check.reason
      };
      violations.push(violation);
      // Track highest risk
      if (RISK_ORDER.indexOf(check.risk) > RISK_ORDER.indexOf(highest_risk)) {
        highest_risk = check.risk;
      }
    }
  }
}

// Determine if safe based on threshold
const highestRiskLevel = RISK_LEVELS[highest_risk] || 1;
const safe = violations.length === 0 || highestRiskLevel < thresholdLevel;

const blocked = violations.filter(v => RISK_LEVELS[v.risk] >= thresholdLevel);

return [{
  json: {
    safe,
    violations,
    summary: {
      total: commands.length,
      checked: commands.length,
      blocked: blocked.length,
      highest_risk,
      risk_threshold: riskThreshold
    }
  }
}];
